update scm_tenant
tenant_name = #{tenantName}, tenant_code = #{tenantCode}, pinyin_code = #{pinyinCode}, status = #{status}, planned_stop_time = #{plannedStopTime}, contact_person = #{contactPerson}, contact_phone = #{contactPhone}, remark = #{remark}, update_by = #{updateBy}, update_time = now()
